starter.javascript:
let savings = 0;
// repeat 4 times: add 5 to savings each pass
// (a count-controlled loop, like REPEAT 4 TIMES)
// then print savings

reference.pseudocode:
savings ← 0
REPEAT 4 TIMES
{
  savings ← savings + 5
}
DISPLAY(savings)

reference.javascript:
let savings = 0;
for (let i = 0; i < 4; i = i + 1) {
  savings = savings + 5;
}
console.log(savings);

starter.javascript:
let savings = 0;
let weeks = 0;
// keep adding 5 to savings until savings reaches 20
// (a condition-controlled loop; REPEAT UNTIL(savings >= 20))
// add 1 to weeks each pass, then print weeks

reference.javascript:
let savings = 0;
let weeks = 0;
while (savings < 20) {
  savings = savings + 5;
  weeks = weeks + 1;
}
console.log(weeks);

starter.javascript:
let savings = 25;
// The condition savings >= 20 is checked BEFORE the first pass.
// Is it already true? If so, how many times does the body run?
// Write the REPEAT UNTIL loop that adds 5, then print savings.

reference.pseudocode:
savings ← 25
REPEAT UNTIL(savings ≥ 20)
{
  savings ← savings + 5
}
DISPLAY(savings)

reference.javascript:
let savings = 25;
while (savings < 20) {
  savings = savings + 5;
}
console.log(savings);

